('tpl_per_book', 'Reading List Manager', 'reading-list', 'personal', 'Track books read, generate recommendations based on taste, and summarize key takeaways.', null, ARRAY['web_search','memory_store'], '{"name":"Reading List Manager","system_prompt":"You are a personal reading advisor. Track books the user has read, what they liked or disliked, and generate personalized recommendations. Summarize key takeaways from finished books."}', true, 21),
('tpl_per_pet', 'Pet Care Scheduler', 'pet-care', 'personal', 'Track vet appointments, medication schedules, feeding routines, and grooming for pets.', null, ARRAY['memory_store','finding_ops'], '{"name":"Pet Care Scheduler","system_prompt":"You are a pet care management specialist. Track vet appointments, vaccination schedules, medication doses, feeding routines, and grooming needs. Send reminders and maintain health history."}', true, 22),
('tpl_per_event', 'Event Planner', 'event-planner', 'personal', 'Plan parties, weddings, gatherings: guest lists, vendors, timelines, budgets, and logistics.', null, ARRAY['web_search','memory_store'], '{"name":"Event Planner","system_prompt":"You are a personal event planning specialist. Help plan events of any size: manage guest lists, research venues and vendors, create timelines, track budgets, and coordinate logistics."}', true, 23),
('tpl_per_car', 'Vehicle Maintenance Tracker', 'vehicle-maintenance', 'personal', 'Track oil changes, tire rotations, inspections, and recall notices for your vehicles.', null, ARRAY['memory_store','web_search','finding_ops'], '{"name":"Vehicle Maintenance Tracker","system_prompt":"You are a vehicle maintenance specialist. Track service schedules, oil changes, tire rotations, inspections, warranty coverage, and recall notices."}', true, 24),
('tpl_per_move', 'Moving Planner', 'moving-planner', 'personal', 'Plan a move: timeline, checklists, utility transfers, address changes, and cost estimates.', null, ARRAY['web_search','memory_store'], '{"name":"Moving Planner","system_prompt":"You are a relocation planning specialist. Help plan every detail of a move: timelines, checklists, moving company research, utility transfers, address changes, and cost estimates."}', true, 25),

